"""
Parameterized generator for GH1006_spaCy_13068.

Source PR:    https://github.com/explosion/spaCy/pull/13068
Source Issue: https://github.com/explosion/spaCy/issues/13056

Seed varies: renames 'append' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH1006_spaCy_13068'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH1006_spaCy_13068'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('append', 'append' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH1006_spaCy_13068',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'explosion/spaCy',
                "pr_number": 13068,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/explosion/spaCy/pull/13068",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'spacy/displacy/render.py': 'import uuid\nfrom typing import Any, Dict, List, Optional, Tuple, Union\n\nfrom ..errors import Errors\nfrom ..util import escape_html, minify_html, registry\nfrom .templates import (\n    TPL_DEP_ARCS,\n    TPL_DEP_SVG,\n    TPL_DEP_WORDS,\n    TPL_DEP_WORDS_LEMMA,\n    TPL_ENT,\n    TPL_ENT_RTL,\n    TPL_ENTS,\n    TPL_FIGURE,\n    TPL_KB_LINK,\n    TPL_PAGE,\n    TPL_SPAN,\n    TPL_SPAN_RTL,\n    TPL_SPAN_SLICE,\n    TPL_SPAN_SLICE_RTL,\n    TPL_SPAN_START,\n    TPL_SPAN_START_RTL,\n    TPL_SPANS,\n    TPL_TITLE,\n)\n\nDEFAULT_LANG = "en"\nDEFAULT_DIR = "ltr"\nDEFAULT_ENTITY_COLOR = "#ddd"\nDEFAULT_LABEL_COLORS = {\n    "ORG": "#7aecec",\n    "PRODUCT": "#bfeeb7",\n    "GPE": "#feca74",\n    "LOC": "#ff9561",\n    "PERSON": "#aa9cfc",\n    "NORP": "#c887fb",\n    "FAC": "#9cc9cc",\n    "EVENT": "#ffeb80",\n    "LAW": "#ff8197",\n    "LANGUAGE": "#ff8197",\n    "WORK_OF_ART": "#f0d0ff",\n    "DATE": "#bfe1d9",\n    "TIME": "#bfe1d9",\n    "MONEY": "#e4e7d2",\n    "QUANTITY": "#e4e7d2",\n    "ORDINAL": "#e4e7d2",\n    "CARDINAL": "#e4e7d2",\n    "PERCENT": "#e4e7d2",\n}\n\n\nclass SpanRenderer:\n    """Render Spans as SVGs."""\n\n    style = "span"\n\n    def __init__(self, options: Dict[str, Any] = {}) -> None:\n        """Initialise span renderer\n\n        options (dict): Visualiser-specific options (colors, spans)\n        """\n        # Set up the colors and overall look\n        colors = dict(DEFAULT_LABEL_COLORS)\n        user_colors = registry.displacy_colors.get_all()\n        for user_color in user_colors.values():\n            if callable(user_color):\n                # Since this comes from the function registry, we want to make\n                # sure we support functions that *return* a dict of colors\n                user_color = user_color()\n            if not isinstance(user_color, dict):\n                raise ValueError(Errors.E925.format(obj=type(user_color)))\n            colors.update(user_color)\n        colors.update(options.get("colors", {}))\n        self.default_color = DEFAULT_ENTITY_COLOR\n        self.colors = {label.upper(): color for label, color in colors.items()}\n\n        # Set up how the text and labels will be rendered\n        self.direction = DEFAULT_DIR\n        self.lang = DEFAULT_LANG\n        # These values are in px\n        self.top_offset = options.get("top_offset", 40)\n        # This is how far under the top offset the span labels appear\n        self.span_label_offset = options.get("span_label_offset", 20)\n        self.offset_step = options.get("top_offset_step", 17)\n\n        # Set up which templates will be used\n        template = options.get("template")\n        if template:\n            self.span_template = template["span"]\n            self.span_slice_template = template["slice"]\n            self.span_start_template = template["start"]\n        else:\n            if self.direction == "rtl":\n                self.span_template = TPL_SPAN_RTL\n                self.span_slice_template = TPL_SPAN_SLICE_RTL\n                self.span_start_template = TPL_SPAN_START_RTL\n            else:\n                self.span_template = TPL_SPAN\n                self.span_slice_template = TPL_SPAN_SLICE\n                self.span_start_template = TPL_SPAN_START\n\n    def render(\n        self, parsed: List[Dict[str, Any]], page: bool = False, minify: bool = False\n    ) -> str:\n        """Render complete markup.\n\n        parsed (list): Dependency parses to render.\n        page (bool): Render parses wrapped as full HTML page.\n        minify (bool): Minify HTML markup.\n        RETURNS (str): Rendered SVG or HTML markup.\n        """\n        rendered = []\n        for i, p in enumerate(parsed):\n            if i == 0:\n                settings = p.get("settings", {})\n                self.direction = settings.get("direction", DEFAULT_DIR)\n                self.lang = settings.get("lang", DEFAULT_LANG)\n            rendered.append(self.render_spans(p["tokens"], p["spans"], p.get("title")))\n\n        if page:\n            docs = "".join([TPL_FIGURE.format(content=doc) for doc in rendered])\n            markup = TPL_PAGE.format(content=docs, lang=self.lang, dir=self.direction)\n        else:\n            markup = "".join(rendered)\n        if minify:\n            return minify_html(markup)\n        return markup\n\n    def render_spans(\n        self,\n        tokens: List[str],\n        spans: List[Dict[str, Any]],\n        title: Optional[str],\n    ) -> str:\n        """Render span types in text.\n\n        Spans are rendered per-token, this means that for each token, we check if it\'s part\n        of a span slice (a member of a span type) or a span start (the starting token of a\n        given span type).\n\n        tokens (list): Individual tokens in the text\n        spans (list): Individual entity spans and their start, end, label, kb_id and kb_url.\n        title (str / None): Document title set in Doc.user_data[\'title\'].\n        """\n        per_token_info = []\n        # we must sort so that we can correctly describe when spans need to "stack"\n        # which is determined by their start token, then span length (longer spans on top),\n        # then break any remaining ties with the span label\n        spans = sorted(\n            spans,\n            key=lambda s: (\n                s["start_token"],\n                -(s["end_token"] - s["start_token"]),\n                s["label"],\n            ),\n        )\n        for s in spans:\n            # this is the vertical \'slot\' that the span will be rendered in\n            # vertical_position = span_label_offset + (offset_step * (slot - 1))\n            s["render_slot"] = 0\n        for idx, token in enumerate(tokens):\n            # Identify if a token belongs to a Span (and which) and if it\'s a\n            # start token of said Span. We\'ll use this for the final HTML render\n            token_markup: Dict[str, Any] = {}\n            token_markup["text"] = token\n            concurrent_spans = 0\n            entities = []\n            for span in spans:\n                ent = {}\n                if span["start_token"] <= idx < span["end_token"]:\n                    concurrent_spans += 1\n                    span_start = idx == span["start_token"]\n                    ent["label"] = span["label"]\n                    ent["is_start"] = span_start\n                    if span_start:\n                        # When the span starts, we need to know how many other\n                        # spans are on the \'span stack\' and will be rendered.\n                        # This value becomes the vertical render slot for this entire span\n                        span["render_slot"] = concurrent_spans\n                    ent["render_slot"] = span["render_slot"]\n                    kb_id = span.get("kb_id", "")\n                    kb_url = span.get("kb_url", "#")\n                    ent["kb_link"] = (\n                        TPL_KB_LINK.format(kb_id=kb_id, kb_url=kb_url) if kb_id else ""\n                    )\n                    entities.append(ent)\n                else:\n                    # We don\'t specifically need to do this since we loop\n                    # over tokens and spans sorted by their start_token,\n                    # so we\'ll never use a span again after the last token it appears in,\n                    # but if we were to use these spans again we\'d want to make sure\n                    # this value was reset correctly.\n                    span["render_slot"] = 0\n            token_markup["entities"] = entities\n            per_token_info.append(token_markup)\n        markup = self._render_markup(per_token_info)\n        markup = TPL_SPANS.format(content=markup, dir=self.direction)\n        if title:\n            markup = TPL_TITLE.format(title=title) + markup\n        return markup\n\n    def _render_markup(self, per_token_info: List[Dict[str, Any]]) -> str:\n        """Render the markup from per-token information"""\n        markup = ""\n        for token in per_token_info:\n            entities = sorted(token["entities"], key=lambda d: d["render_slot"])\n            # Whitespace tokens disrupt the vertical space (no line height) so that the\n            # span indicators get misaligned. We don\'t render them as individual\n            # tokens anyway, so we\'ll just not display a span indicator either.\n            is_whitespace = token["text"].strip() == ""\n            if entities and not is_whitespace:\n                slices = self._get_span_slices(token["entities"])\n                starts = self._get_span_starts(token["entities"])\n                total_height = (\n                    self.top_offset\n                    + self.span_label_offset\n                    + (self.offset_step * (len(entities) - 1))\n                )\n                markup += self.span_template.format(\n                    text=escape_html(token["text"]),\n                    span_slices=slices,\n                    span_starts=starts,\n                    total_height=total_height,\n                )\n            else:\n                markup += escape_html(token["text"] + " ")\n        return markup\n\n    def _get_span_slices(self, entities: List[Dict]) -> str:\n        """Get the rendered markup of all Span slices"""\n        span_slices = []\n        for entity in entities:\n            # rather than iterate over multiples of offset_step, we use entity[\'render_slot\']\n            # to determine the vertical position, since that tells where\n            # the span starts vertically so we can extend it horizontally,\n            # past other spans that might have already ended\n            color = self.colors.get(entity["label"].upper(), self.default_color)\n            top_offset = self.top_offset + (\n                self.offset_step * (entity["render_slot"] - 1)\n            )\n            span_slice = self.span_slice_template.format(\n                bg=color,\n                top_offset=top_offset,\n            )\n            span_slices.append(span_slice)\n        return "".join(span_slices)\n\n    def _get_span_starts(self, entities: List[Dict]) -> str:\n        """Get the rendered markup of all Span start tokens"""\n        span_starts = []\n        for entity in entities:\n            color = self.colors.get(entity["label"].upper(), self.default_color)\n            top_offset = self.top_offset + (\n                self.offset_step * (entity["render_slot"] - 1)\n            )\n            span_start = (\n                self.span_start_template.format(\n                    bg=color,\n                    top_offset=top_offset,\n                    label=entity["label"],\n                    kb_link=entity["kb_link"],\n                )\n                if entity["is_start"]\n                else ""\n            )\n            span_starts.append(span_start)\n        return "".join(span_starts)\n\n\nclass DependencyRenderer:\n    """Render dependency parses as SVGs."""\n\n    style = "dep"\n\n    def __init__(self, options: Dict[str, Any] = {}) -> None:\n        """Initialise dependency renderer.\n\n        options (dict): Visualiser-specific options (compact, word_spacing,\n            arrow_spacing, arrow_width, arrow_stroke, distance, offset_x,\n            color, bg, font)\n        """\n        self.compact = options.get("compact", False)\n        self.word_spacing = options.get("word_spacing", 45)\n        self.arrow_spacing = options.get("arrow_spacing", 12 if self.compact else 20)\n        self.arrow_width = options.get("arrow_width", 6 if self.compact else 10)\n        self.arrow_stroke = options.get("arrow_stroke", 2)\n        self.distance = options.get("distance", 150 if self.compact else 175)\n        self.offset_x = options.get("offset_x", 50)\n        self.color = options.get("color", "#000000")\n        self.bg = options.get("bg", "#ffffff")\n        self.font = options.get("font", "Arial")\n        self.direction = DEFAULT_DIR\n        self.lang = DEFAULT_LANG\n\n    def render(\n        self, parsed: List[Dict[str, Any]], page: bool = False, minify: bool = False\n    ) -> str:\n        """Render complete markup.\n\n        parsed (list): Dependency parses to render.\n        page (bool): Render parses wrapped as full HTML page.\n        minify (bool): Minify HTML markup.\n        RETURNS (str): Rendered SVG or HTML markup.\n        """\n        # Create a random ID prefix to make sure parses don\'t receive the\n        # same ID, even if they\'re identical\n        id_prefix = uuid.uuid4().hex\n        rendered = []\n        for i, p in enumerate(parsed):\n            if i == 0:\n                settings = p.get("settings", {})\n                self.direction = settings.get("direction", DEFAULT_DIR)\n                self.lang = settings.get("lang", DEFAULT_LANG)\n            render_id = f"{id_prefix}-{i}"\n            svg = self.render_svg(render_id, p["words"], p["arcs"])\n            if p.get("title"):\n                svg = TPL_TITLE.format(title=p.get("title")) + svg\n            rendered.append(svg)\n        if page:\n            content = "".join([TPL_FIGURE.format(content=svg) for svg in rendered])\n            markup = TPL_PAGE.format(\n                content=content, lang=self.lang, dir=self.direction\n            )\n        else:\n            markup = "".join(rendered)\n        if minify:\n            return minify_html(markup)\n        return markup\n\n    def render_svg(\n        self,\n        render_id: Union[int, str],\n        words: List[Dict[str, Any]],\n        arcs: List[Dict[str, Any]],\n    ) -> str:\n        """Render SVG.\n\n        render_id (Union[int, str]): Unique ID, typically index of document.\n        words (list): Individual words and their tags.\n        arcs (list): Individual arcs and their start, end, direction and label.\n        RETURNS (str): Rendered SVG markup.\n        """\n        self.levels = self.get_levels(arcs)\n        self.highest_level = max(self.levels.values(), default=0)\n        self.offset_y = self.distance / 2 * self.highest_level + self.arrow_stroke\n        self.width = self.offset_x + len(words) * self.distance\n        self.height = self.offset_y + 3 * self.word_spacing\n        self.id = render_id\n        words_svg = [\n            self.render_word(w["text"], w["tag"], w.get("lemma", None), i)\n            for i, w in enumerate(words)\n        ]\n        arcs_svg = [\n            self.render_arrow(a["label"], a["start"], a["end"], a["dir"], i)\n            for i, a in enumerate(arcs)\n        ]\n        content = "".join(words_svg) + "".join(arcs_svg)\n        return TPL_DEP_SVG.format(\n            id=self.id,\n            width=self.width,\n            height=self.height,\n            color=self.color,\n            bg=self.bg,\n            font=self.font,\n            content=content,\n            dir=self.direction,\n            lang=self.lang,\n        )\n\n    def render_word(self, text: str, tag: str, lemma: str, i: int) -> str:\n        """Render individual word.\n\n        text (str): Word text.\n        tag (str): Part-of-speech tag.\n        i (int): Unique ID, typically word index.\n        RETURNS (str): Rendered SVG markup.\n        """\n        y = self.offset_y + self.word_spacing\n        x = self.offset_x + i * self.distance\n        if self.direction == "rtl":\n            x = self.width - x\n        html_text = escape_html(text)\n        if lemma is not None:\n            return TPL_DEP_WORDS_LEMMA.format(\n                text=html_text, tag=tag, lemma=lemma, x=x, y=y\n            )\n        return TPL_DEP_WORDS.format(text=html_text, tag=tag, x=x, y=y)\n\n    def render_arrow(\n        self, label: str, start: int, end: int, direction: str, i: int\n    ) -> str:\n        """Render individual arrow.\n\n        label (str): Dependency label.\n        start (int): Index of start word.\n        end (int): Index of end word.\n        direction (str): Arrow direction, \'left\' or \'right\'.\n        i (int): Unique ID, typically arrow index.\n        RETURNS (str): Rendered SVG markup.\n        """\n        if start < 0 or end < 0:\n            error_args = dict(start=start, end=end, label=label, dir=direction)\n            raise ValueError(Errors.E157.format(**error_args))\n        level = self.levels[(start, end, label)]\n        x_start = self.offset_x + start * self.distance + self.arrow_spacing\n        if self.direction == "rtl":\n            x_start = self.width - x_start\n        y = self.offset_y\n        x_end = (\n            self.offset_x\n            + (end - start) * self.distance\n            + start * self.distance\n            - self.arrow_spacing * (self.highest_level - level) / 4\n        )\n        if self.direction == "rtl":\n            x_end = self.width - x_end\n        y_curve = self.offset_y - level * self.distance / 2\n        if self.compact:\n            y_curve = self.offset_y - level * self.distance / 6\n        if y_curve == 0 and max(self.levels.values(), default=0) > 5:\n            y_curve = -self.distance\n        arrowhead = self.get_arrowhead(direction, x_start, y, x_end)\n        arc = self.get_arc(x_start, y, y_curve, x_end)\n        label_side = "right" if self.direction == "rtl" else "left"\n        return TPL_DEP_ARCS.format(\n            id=self.id,\n            i=i,\n            stroke=self.arrow_stroke,\n            head=arrowhead,\n            label=label,\n            label_side=label_side,\n            arc=arc,\n        )\n\n    def get_arc(self, x_start: int, y: int, y_curve: int, x_end: int) -> str:\n        """Render individual arc.\n\n        x_start (int): X-coordinate of arrow start point.\n        y (int): Y-coordinate of arrow start and end point.\n        y_curve (int): Y-corrdinate of Cubic Bézier y_curve point.\n        x_end (int): X-coordinate of arrow end point.\n        RETURNS (str): Definition of the arc path (\'d\' attribute).\n        """\n        template = "M{x},{y} C{x},{c} {e},{c} {e},{y}"\n        if self.compact:\n            template = "M{x},{y} {x},{c} {e},{c} {e},{y}"\n        return template.format(x=x_start, y=y, c=y_curve, e=x_end)\n\n    def get_arrowhead(self, direction: str, x: int, y: int, end: int) -> str:\n        """Render individual arrow head.\n\n        direction (str): Arrow direction, \'left\' or \'right\'.\n        x (int): X-coordinate of arrow start point.\n        y (int): Y-coordinate of arrow start and end point.\n        end (int): X-coordinate of arrow end point.\n        RETURNS (str): Definition of the arrow head path (\'d\' attribute).\n        """\n        if direction == "left":\n            p1, p2, p3 = (x, x - self.arrow_width + 2, x + self.arrow_width - 2)\n        else:\n            p1, p2, p3 = (end, end + self.arrow_width - 2, end - self.arrow_width + 2)\n        return f"M{p1},{y + 2} L{p2},{y - self.arrow_width} {p3},{y - self.arrow_width}"\n\n    def get_levels(self, arcs: List[Dict[str, Any]]) -> Dict[Tuple[int, int, str], int]:\n        """Calculate available arc height "levels".\n        Used to calculate arrow heights dynamically and without wasting space.\n\n        args (list): Individual arcs and their start, end, direction and label.\n        RETURNS (dict): Arc levels keyed by (start, end, label).\n        """\n        arcs = [dict(t) for t in {tuple(sorted(arc.items())) for arc in arcs}]\n        length = max([arc["end"] for arc in arcs], default=0)\n        max_level = [0] * length\n        levels = {}\n        for arc in sorted(arcs, key=lambda arc: arc["end"] - arc["start"]):\n            level = max(max_level[arc["start"] : arc["end"]]) + 1\n            for i in range(arc["start"], arc["end"]):\n                max_level[i] = level\n            levels[(arc["start"], arc["end"], arc["label"])] = level\n        return levels\n\n\nclass EntityRenderer:\n    """Render named entities as HTML."""\n\n    style = "ent"\n\n    def __init__(self, options: Dict[str, Any] = {}) -> None:\n        """Initialise entity renderer.\n\n        options (dict): Visualiser-specific options (colors, ents)\n        """\n        colors = dict(DEFAULT_LABEL_COLORS)\n        user_colors = registry.displacy_colors.get_all()\n        for user_color in user_colors.values():\n            if callable(user_color):\n                # Since this comes from the function registry, we want to make\n                # sure we support functions that *return* a dict of colors\n                user_color = user_color()\n            if not isinstance(user_color, dict):\n                raise ValueError(Errors.E925.format(obj=type(user_color)))\n            colors.update(user_color)\n        colors.update(options.get("colors", {}))\n        self.default_color = DEFAULT_ENTITY_COLOR\n        self.colors = {label.upper(): color for label, color in colors.items()}\n        self.ents = options.get("ents", None)\n        if self.ents is not None:\n            self.ents = [ent.upper() for ent in self.ents]\n        self.direction = DEFAULT_DIR\n        self.lang = DEFAULT_LANG\n        template = options.get("template")\n        if template:\n            self.ent_template = template\n        else:\n            if self.direction == "rtl":\n                self.ent_template = TPL_ENT_RTL\n            else:\n                self.ent_template = TPL_ENT\n\n    def render(\n        self, parsed: List[Dict[str, Any]], page: bool = False, minify: bool = False\n    ) -> str:\n        """Render complete markup.\n\n        parsed (list): Dependency parses to render.\n        page (bool): Render parses wrapped as full HTML page.\n        minify (bool): Minify HTML markup.\n        RETURNS (str): Rendered SVG or HTML markup.\n        """\n        rendered = []\n        for i, p in enumerate(parsed):\n            if i == 0:\n                settings = p.get("settings", {})\n                self.direction = settings.get("direction", DEFAULT_DIR)\n                self.lang = settings.get("lang", DEFAULT_LANG)\n            rendered.append(self.render_ents(p["text"], p["ents"], p.get("title")))\n        if page:\n            docs = "".join([TPL_FIGURE.format(content=doc) for doc in rendered])\n            markup = TPL_PAGE.format(content=docs, lang=self.lang, dir=self.direction)\n        else:\n            markup = "".join(rendered)\n        if minify:\n            return minify_html(markup)\n        return markup\n\n    def render_ents(\n        self, text: str, spans: List[Dict[str, Any]], title: Optional[str]\n    ) -> str:\n        """Render entities in text.\n\n        text (str): Original text.\n        spans (list): Individual entity spans and their start, end, label, kb_id and kb_url.\n        title (str / None): Document title set in Doc.user_data[\'title\'].\n        """\n        markup = ""\n        offset = 0\n        for span in spans:\n            label = span["label"]\n            start = span["start"]\n            end = span["end"]\n            kb_id = span.get("kb_id", "")\n            kb_url = span.get("kb_url", "#")\n            kb_link = TPL_KB_LINK.format(kb_id=kb_id, kb_url=kb_url) if kb_id else ""\n            additional_params = span.get("params", {})\n            entity = escape_html(text[start:end])\n            fragments = text[offset:start].split("\\n")\n            for i, fragment in enumerate(fragments):\n                markup += escape_html(fragment)\n                if len(fragments) > 1 and i != len(fragments) - 1:\n                    markup += "<br>"\n            if self.ents is None or label.upper() in self.ents:\n                color = self.colors.get(label.upper(), self.default_color)\n                ent_settings = {\n                    "label": label,\n                    "text": entity,\n                    "bg": color,\n                    "kb_link": kb_link,\n                }\n                ent_settings.update(additional_params)\n                markup += self.ent_template.format(**ent_settings)\n            else:\n                markup += entity\n            offset = end\n        fragments = text[offset:].split("\\n")\n        for i, fragment in enumerate(fragments):\n            markup += escape_html(fragment)\n            if len(fragments) > 1 and i != len(fragments) - 1:\n                markup += "<br>"\n        markup = TPL_ENTS.format(content=markup, dir=self.direction)\n        if title:\n            markup = TPL_TITLE.format(title=title) + markup\n        return markup\n',
            'spacy/tests/test_displacy.py': 'import numpy\nimport pytest\n\nfrom spacy import displacy\nfrom spacy.displacy.render import DependencyRenderer, EntityRenderer\nfrom spacy.lang.en import English\nfrom spacy.lang.fa import Persian\nfrom spacy.tokens import Doc, Span\n\n\n@pytest.mark.issue(2361)\ndef test_issue2361(de_vocab):\n    """Test if < is escaped when rendering"""\n    chars = ("&lt;", "&gt;", "&amp;", "&quot;")\n    words = ["<", ">", "&", \'"\']\n    doc = Doc(de_vocab, words=words, deps=["dep"] * len(words))\n    html = displacy.render(doc)\n    for char in chars:\n        assert char in html\n\n\n@pytest.mark.issue(2728)\ndef test_issue2728(en_vocab):\n    """Test that displaCy ENT visualizer escapes HTML correctly."""\n    doc = Doc(en_vocab, words=["test", "<RELEASE>", "test"])\n    doc.ents = [Span(doc, 0, 1, label="TEST")]\n    html = displacy.render(doc, style="ent")\n    assert "&lt;RELEASE&gt;" in html\n    doc.ents = [Span(doc, 1, 2, label="TEST")]\n    html = displacy.render(doc, style="ent")\n    assert "&lt;RELEASE&gt;" in html\n\n\n@pytest.mark.issue(3288)\ndef test_issue3288(en_vocab):\n    """Test that retokenization works correctly via displaCy when punctuation\n    is merged onto the preceeding token and tensor is resized."""\n    words = ["Hello", "World", "!", "When", "is", "this", "breaking", "?"]\n    heads = [1, 1, 1, 4, 4, 6, 4, 4]\n    deps = ["intj", "ROOT", "punct", "advmod", "ROOT", "det", "nsubj", "punct"]\n    doc = Doc(en_vocab, words=words, heads=heads, deps=deps)\n    doc.tensor = numpy.zeros((len(words), 96), dtype="float32")\n    displacy.render(doc)\n\n\n@pytest.mark.issue(3531)\ndef test_issue3531():\n    """Test that displaCy renderer doesn\'t require "settings" key."""\n    example_dep = {\n        "words": [\n            {"text": "But", "tag": "CCONJ"},\n            {"text": "Google", "tag": "PROPN"},\n            {"text": "is", "tag": "VERB"},\n            {"text": "starting", "tag": "VERB"},\n            {"text": "from", "tag": "ADP"},\n            {"text": "behind.", "tag": "ADV"},\n        ],\n        "arcs": [\n            {"start": 0, "end": 3, "label": "cc", "dir": "left"},\n            {"start": 1, "end": 3, "label": "nsubj", "dir": "left"},\n            {"start": 2, "end": 3, "label": "aux", "dir": "left"},\n            {"start": 3, "end": 4, "label": "prep", "dir": "right"},\n            {"start": 4, "end": 5, "label": "pcomp", "dir": "right"},\n        ],\n    }\n    example_ent = {\n        "text": "But Google is starting from behind.",\n        "ents": [{"start": 4, "end": 10, "label": "ORG"}],\n    }\n    dep_html = displacy.render(example_dep, style="dep", manual=True)\n    assert dep_html\n    ent_html = displacy.render(example_ent, style="ent", manual=True)\n    assert ent_html\n\n\n@pytest.mark.issue(3882)\ndef test_issue3882(en_vocab):\n    """Test that displaCy doesn\'t serialize the doc.user_data when making a\n    copy of the Doc.\n    """\n    doc = Doc(en_vocab, words=["Hello", "world"], deps=["dep", "dep"])\n    doc.user_data["test"] = set()\n    displacy.parse_deps(doc)\n\n\n@pytest.mark.issue(5447)\ndef test_issue5447():\n    """Test that overlapping arcs get separate levels, unless they\'re identical."""\n    renderer = DependencyRenderer()\n    words = [\n        {"text": "This", "tag": "DT"},\n        {"text": "is", "tag": "VBZ"},\n        {"text": "a", "tag": "DT"},\n        {"text": "sentence.", "tag": "NN"},\n    ]\n    arcs = [\n        {"start": 0, "end": 1, "label": "nsubj", "dir": "left"},\n        {"start": 2, "end": 3, "label": "det", "dir": "left"},\n        {"start": 2, "end": 3, "label": "overlap", "dir": "left"},\n        {"end": 3, "label": "overlap", "start": 2, "dir": "left"},\n        {"start": 1, "end": 3, "label": "attr", "dir": "left"},\n    ]\n    renderer.render([{"words": words, "arcs": arcs}])\n    assert renderer.highest_level == 3\n\n\n@pytest.mark.issue(5838)\ndef test_issue5838():\n    # Displacy\'s EntityRenderer break line\n    # not working after last entity\n    sample_text = "First line\\nSecond line, with ent\\nThird line\\nFourth line\\n"\n    nlp = English()\n    doc = nlp(sample_text)\n    doc.ents = [Span(doc, 7, 8, label="test")]\n    html = displacy.render(doc, style="ent")\n    found = html.count("<br>")\n    assert found == 4\n\n\ndef test_displacy_parse_spans(en_vocab):\n    """Test that spans on a Doc are converted into displaCy\'s format."""\n    doc = Doc(en_vocab, words=["Welcome", "to", "the", "Bank", "of", "China"])\n    doc.spans["sc"] = [Span(doc, 3, 6, "ORG"), Span(doc, 5, 6, "GPE")]\n    spans = displacy.parse_spans(doc)\n    assert isinstance(spans, dict)\n    assert spans["text"] == "Welcome to the Bank of China "\n    assert spans["spans"] == [\n        {\n            "start": 15,\n            "end": 28,\n            "start_token": 3,\n            "end_token": 6,\n            "label": "ORG",\n            "kb_id": "",\n            "kb_url": "#",\n        },\n        {\n            "start": 23,\n            "end": 28,\n            "start_token": 5,\n            "end_token": 6,\n            "label": "GPE",\n            "kb_id": "",\n            "kb_url": "#",\n        },\n    ]\n\n\ndef test_displacy_parse_spans_with_kb_id_options(en_vocab):\n    """Test that spans with kb_id on a Doc are converted into displaCy\'s format"""\n    doc = Doc(en_vocab, words=["Welcome", "to", "the", "Bank", "of", "China"])\n    doc.spans["sc"] = [\n        Span(doc, 3, 6, "ORG", kb_id="Q790068"),\n        Span(doc, 5, 6, "GPE", kb_id="Q148"),\n    ]\n\n    spans = displacy.parse_spans(\n        doc, {"kb_url_template": "https://wikidata.org/wiki/{}"}\n    )\n    assert isinstance(spans, dict)\n    assert spans["text"] == "Welcome to the Bank of China "\n    assert spans["spans"] == [\n        {\n            "start": 15,\n            "end": 28,\n            "start_token": 3,\n            "end_token": 6,\n            "label": "ORG",\n            "kb_id": "Q790068",\n            "kb_url": "https://wikidata.org/wiki/Q790068",\n        },\n        {\n            "start": 23,\n            "end": 28,\n            "start_token": 5,\n            "end_token": 6,\n            "label": "GPE",\n            "kb_id": "Q148",\n            "kb_url": "https://wikidata.org/wiki/Q148",\n        },\n    ]\n\n\ndef test_displacy_parse_spans_different_spans_key(en_vocab):\n    """Test that spans in a different spans key will be parsed"""\n    doc = Doc(en_vocab, words=["Welcome", "to", "the", "Bank", "of", "China"])\n    doc.spans["sc"] = [Span(doc, 3, 6, "ORG"), Span(doc, 5, 6, "GPE")]\n    doc.spans["custom"] = [Span(doc, 3, 6, "BANK")]\n    spans = displacy.parse_spans(doc, options={"spans_key": "custom"})\n\n    assert isinstance(spans, dict)\n    assert spans["text"] == "Welcome to the Bank of China "\n    assert spans["spans"] == [\n        {\n            "start": 15,\n            "end": 28,\n            "start_token": 3,\n            "end_token": 6,\n            "label": "BANK",\n            "kb_id": "",\n            "kb_url": "#",\n        }\n    ]\n\n\ndef test_displacy_parse_empty_spans_key(en_vocab):\n    """Test that having an unset spans key doesn\'t raise an error"""\n    doc = Doc(en_vocab, words=["Welcome", "to", "the", "Bank", "of", "China"])\n    doc.spans["custom"] = [Span(doc, 3, 6, "BANK")]\n    with pytest.warns(UserWarning, match="W117"):\n        spans = displacy.parse_spans(doc)\n\n    assert isinstance(spans, dict)\n\n\ndef test_displacy_parse_ents(en_vocab):\n    """Test that named entities on a Doc are converted into displaCy\'s format."""\n    doc = Doc(en_vocab, words=["But", "Google", "is", "starting", "from", "behind"])\n    doc.ents = [Span(doc, 1, 2, label=doc.vocab.strings["ORG"])]\n    ents = displacy.parse_ents(doc)\n    assert isinstance(ents, dict)\n    assert ents["text"] == "But Google is starting from behind "\n    assert ents["ents"] == [\n        {"start": 4, "end": 10, "label": "ORG", "kb_id": "", "kb_url": "#"}\n    ]\n\n    doc.ents = [Span(doc, 1, 2, label=doc.vocab.strings["ORG"], kb_id="Q95")]\n    ents = displacy.parse_ents(doc)\n    assert isinstance(ents, dict)\n    assert ents["text"] == "But Google is starting from behind "\n    assert ents["ents"] == [\n        {"start": 4, "end": 10, "label": "ORG", "kb_id": "Q95", "kb_url": "#"}\n    ]\n\n\ndef test_displacy_parse_ents_with_kb_id_options(en_vocab):\n    """Test that named entities with kb_id on a Doc are converted into displaCy\'s format."""\n    doc = Doc(en_vocab, words=["But", "Google", "is", "starting", "from", "behind"])\n    doc.ents = [Span(doc, 1, 2, label=doc.vocab.strings["ORG"], kb_id="Q95")]\n\n    ents = displacy.parse_ents(\n        doc, {"kb_url_template": "https://www.wikidata.org/wiki/{}"}\n    )\n    assert isinstance(ents, dict)\n    assert ents["text"] == "But Google is starting from behind "\n    assert ents["ents"] == [\n        {\n            "start": 4,\n            "end": 10,\n            "label": "ORG",\n            "kb_id": "Q95",\n            "kb_url": "https://www.wikidata.org/wiki/Q95",\n        }\n    ]\n\n\ndef test_displacy_parse_deps(en_vocab):\n    """Test that deps and tags on a Doc are converted into displaCy\'s format."""\n    words = ["This", "is", "a", "sentence"]\n    heads = [1, 1, 3, 1]\n    pos = ["DET", "VERB", "DET", "NOUN"]\n    tags = ["DT", "VBZ", "DT", "NN"]\n    deps = ["nsubj", "ROOT", "det", "attr"]\n    doc = Doc(en_vocab, words=words, heads=heads, pos=pos, tags=tags, deps=deps)\n    deps = displacy.parse_deps(doc)\n    assert isinstance(deps, dict)\n    assert deps["words"] == [\n        {"lemma": None, "text": words[0], "tag": pos[0]},\n        {"lemma": None, "text": words[1], "tag": pos[1]},\n        {"lemma": None, "text": words[2], "tag": pos[2]},\n        {"lemma": None, "text": words[3], "tag": pos[3]},\n    ]\n    assert deps["arcs"] == [\n        {"start": 0, "end": 1, "label": "nsubj", "dir": "left"},\n        {"start": 2, "end": 3, "label": "det", "dir": "left"},\n        {"start": 1, "end": 3, "label": "attr", "dir": "right"},\n    ]\n    # Test that displacy.parse_deps converts Span to Doc\n    deps = displacy.parse_deps(doc[:])\n    assert isinstance(deps, dict)\n    assert deps["words"] == [\n        {"lemma": None, "text": words[0], "tag": pos[0]},\n        {"lemma": None, "text": words[1], "tag": pos[1]},\n        {"lemma": None, "text": words[2], "tag": pos[2]},\n        {"lemma": None, "text": words[3], "tag": pos[3]},\n    ]\n    assert deps["arcs"] == [\n        {"start": 0, "end": 1, "label": "nsubj", "dir": "left"},\n        {"start": 2, "end": 3, "label": "det", "dir": "left"},\n        {"start": 1, "end": 3, "label": "attr", "dir": "right"},\n    ]\n\n\ndef test_displacy_invalid_arcs():\n    renderer = DependencyRenderer()\n    words = [{"text": "This", "tag": "DET"}, {"text": "is", "tag": "VERB"}]\n    arcs = [\n        {"start": 0, "end": 1, "label": "nsubj", "dir": "left"},\n        {"start": -1, "end": 2, "label": "det", "dir": "left"},\n    ]\n    with pytest.raises(ValueError):\n        renderer.render([{"words": words, "arcs": arcs}])\n\n\ndef test_displacy_spans(en_vocab):\n    """Test that displaCy can render Spans."""\n    doc = Doc(en_vocab, words=["But", "Google", "is", "starting", "from", "behind"])\n    doc.ents = [Span(doc, 1, 2, label=doc.vocab.strings["ORG"])]\n    html = displacy.render(doc[1:4], style="ent")\n    assert html.startswith("<div")\n\n\ndef test_displacy_raises_for_wrong_type(en_vocab):\n    with pytest.raises(ValueError):\n        displacy.render("hello world")\n\n\ndef test_displacy_rtl():\n    # Source: http://www.sobhe.ir/hazm/ – is this correct?\n    words = ["ما", "بسیار", "کتاب", "می\\u200cخوانیم"]\n    # These are (likely) wrong, but it\'s just for testing\n    pos = ["PRO", "ADV", "N_PL", "V_SUB"]  # needs to match lang.fa.tag_map\n    deps = ["foo", "bar", "foo", "baz"]\n    heads = [1, 0, 3, 1]\n    nlp = Persian()\n    doc = Doc(nlp.vocab, words=words, tags=pos, heads=heads, deps=deps)\n    doc.ents = [Span(doc, 1, 3, label="TEST")]\n    html = displacy.render(doc, page=True, style="dep")\n    assert "direction: rtl" in html\n    assert \'direction="rtl"\' in html\n    assert f\'lang="{nlp.lang}"\' in html\n    html = displacy.render(doc, page=True, style="ent")\n    assert "direction: rtl" in html\n    assert f\'lang="{nlp.lang}"\' in html\n\n\ndef test_displacy_render_wrapper(en_vocab):\n    """Test that displaCy accepts custom rendering wrapper."""\n\n    def wrapper(html):\n        return "TEST" + html + "TEST"\n\n    displacy.set_render_wrapper(wrapper)\n    doc = Doc(en_vocab, words=["But", "Google", "is", "starting", "from", "behind"])\n    doc.ents = [Span(doc, 1, 2, label=doc.vocab.strings["ORG"])]\n    html = displacy.render(doc, style="ent")\n    assert html.startswith("TEST<div")\n    assert html.endswith("/div>TEST")\n    # Restore\n    displacy.set_render_wrapper(lambda html: html)\n\n\ndef test_displacy_render_manual_dep():\n    """Test displacy.render with manual data for dep style"""\n    parsed_dep = {\n        "words": [\n            {"text": "This", "tag": "DT"},\n            {"text": "is", "tag": "VBZ"},\n            {"text": "a", "tag": "DT"},\n            {"text": "sentence", "tag": "NN"},\n        ],\n        "arcs": [\n            {"start": 0, "end": 1, "label": "nsubj", "dir": "left"},\n            {"start": 2, "end": 3, "label": "det", "dir": "left"},\n            {"start": 1, "end": 3, "label": "attr", "dir": "right"},\n        ],\n        "title": "Title",\n    }\n    html = displacy.render([parsed_dep], style="dep", manual=True)\n    for word in parsed_dep["words"]:\n        assert word["text"] in html\n        assert word["tag"] in html\n\n\ndef test_displacy_render_manual_ent():\n    """Test displacy.render with manual data for ent style"""\n    parsed_ents = [\n        {\n            "text": "But Google is starting from behind.",\n            "ents": [{"start": 4, "end": 10, "label": "ORG"}],\n        },\n        {\n            "text": "But Google is starting from behind.",\n            "ents": [{"start": -100, "end": 100, "label": "COMPANY"}],\n            "title": "Title",\n        },\n    ]\n\n    html = displacy.render(parsed_ents, style="ent", manual=True)\n    for parsed_ent in parsed_ents:\n        assert parsed_ent["ents"][0]["label"] in html\n        if "title" in parsed_ent:\n            assert parsed_ent["title"] in html\n\n\ndef test_displacy_render_manual_span():\n    """Test displacy.render with manual data for span style"""\n    parsed_spans = [\n        {\n            "text": "Welcome to the Bank of China.",\n            "spans": [\n                {"start_token": 3, "end_token": 6, "label": "ORG"},\n                {"start_token": 5, "end_token": 6, "label": "GPE"},\n            ],\n            "tokens": ["Welcome", "to", "the", "Bank", "of", "China", "."],\n        },\n        {\n            "text": "Welcome to the Bank of China.",\n            "spans": [\n                {"start_token": 3, "end_token": 6, "label": "ORG"},\n                {"start_token": 5, "end_token": 6, "label": "GPE"},\n            ],\n            "tokens": ["Welcome", "to", "the", "Bank", "of", "China", "."],\n            "title": "Title",\n        },\n    ]\n\n    html = displacy.render(parsed_spans, style="span", manual=True)\n    for parsed_span in parsed_spans:\n        assert parsed_span["spans"][0]["label"] in html\n        if "title" in parsed_span:\n            assert parsed_span["title"] in html\n\n\ndef test_displacy_options_case():\n    ents = ["foo", "BAR"]\n    colors = {"FOO": "red", "bar": "green"}\n    renderer = EntityRenderer({"ents": ents, "colors": colors})\n    text = "abcd"\n    labels = ["foo", "bar", "FOO", "BAR"]\n    spans = [{"start": i, "end": i + 1, "label": labels[i]} for i in range(len(text))]\n    result = renderer.render_ents("abcde", spans, None).split("\\n\\n")\n    assert "red" in result[0] and "foo" in result[0]\n    assert "green" in result[1] and "bar" in result[1]\n    assert "red" in result[2] and "FOO" in result[2]\n    assert "green" in result[3] and "BAR" in result[3]\n\n\n@pytest.mark.issue(10672)\ndef test_displacy_manual_sorted_entities():\n    doc = {\n        "text": "But Google is starting from behind.",\n        "ents": [\n            {"start": 14, "end": 22, "label": "SECOND"},\n            {"start": 4, "end": 10, "label": "FIRST"},\n        ],\n        "title": None,\n    }\n\n    html = displacy.render(doc, style="ent", manual=True)\n    assert html.find("FIRST") < html.find("SECOND")\n\n\n@pytest.mark.issue(12816)\ndef test_issue12816(en_vocab) -> None:\n    """Test that displaCy\'s span visualizer escapes annotated HTML tags correctly."""\n    # Create a doc containing an annotated word and an unannotated HTML tag\n    doc = Doc(en_vocab, words=["test", "<TEST>"])\n    doc.spans["sc"] = [Span(doc, 0, 1, label="test")]\n\n    # Verify that the HTML tag is escaped when unannotated\n    html = displacy.render(doc, style="span")\n    assert "&lt;TEST&gt;" in html\n\n    # Annotate the HTML tag\n    doc.spans["sc"].append(Span(doc, 1, 2, label="test"))\n\n    # Verify that the HTML tag is still escaped\n    html = displacy.render(doc, style="span")\n    assert "&lt;TEST&gt;" in html\n',
        }
